#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        long long *a = (long long*)malloc(N * sizeof(long long));
        long long *ans = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &a[i]);
        long long pref = 1;
        for (int i = 0; i < N; ++i) {
            ans[i] = pref;
            pref *= a[i];
        }
        long long suff = 1;
        for (int i = N - 1; i >= 0; --i) {
            ans[i] *= suff;
            suff *= a[i];
        }
        for (int i = 0; i < N; ++i) {
            if (i) printf(" ");
            printf("%lld", ans[i]);
        }
        printf("\n");
        free(a);
        free(ans);
    }
    return 0;
}

