const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
for (let tc = 0; tc < T; ++tc) {
  const N = input[idx++];
  const arr = input.slice(idx, idx + N);
  idx += N;
  const ans = new Array(N);
  let pref = 1;
  for (let i = 0; i < N; ++i) {
    ans[i] = pref;
    pref *= arr[i];
  }
  let suff = 1;
  for (let i = N - 1; i >= 0; --i) {
    ans[i] *= suff;
    suff *= arr[i];
  }
  outputs.push(ans.join(' '));
}
